+): void {
+  QMD_MANAGER_OPEN_FAILURES.set(scopeKey, {
+    identityKey,
+    reason,
+    retryAfterMs: nowMs + QMD_MANAGER_OPEN_FAILURE_COOLDOWN_MS,
+  });
+}
